(function () {
'use strict';
var KNOWN_PERMISSION_SLUGS = [
'role_view_dashboard',
'role_manage_items',
'role_view_sales',
'role_process_sales',
'role_void_sales',
'role_manage_gift_cards',
'role_view_reports',
'role_manage_vendors',
'role_manage_rent',
'role_import_data',
'role_change_settings',
'role_balance_adjustments',
'role_print_labels',
'role_view_ai_assistant',
'role_manage_studio',
'role_inventory_verify'
];
var _sessionCache = null;
function _truthy(value) {
return value === true || value === 'true' || value === '1' || value === 1;
}
function _getBoothMode() {
try {
return sessionStorage.getItem('bmm_booth_mode') === '1';
} catch (e) {
return false;
}
}
function _clearBoothMode() {
try {
sessionStorage.removeItem('bmm_booth_mode');
} catch (e) {}
}
function _normalizePermissions(role, permissions) {
var normalized = {};
permissions = permissions || {};
KNOWN_PERMISSION_SLUGS.forEach(function (slug) {
normalized[slug] = role === 'admin' ? true : _truthy(permissions[slug]);
});
Object.keys(permissions).forEach(function (key) {
if (!Object.prototype.hasOwnProperty.call(normalized, key)) {
normalized[key] = role === 'admin' ? true : _truthy(permissions[key]);
}
});
return normalized;
}
function _deriveSession(data) {
var role = data.role || '';
var permissions = _normalizePermissions(role, data.permissions);
var isStaff = role === 'admin' || role === 'cashier';
var isVendor = !!data.is_vendor || role === 'vendor';
var boothMode = _getBoothMode();
if (role === 'admin' && boothMode) {
_clearBoothMode();
boothMode = false;
}
var canAccessVendorBooth = role === 'vendor' || (isVendor && boothMode);
return {
id: data.id,
role: role,
name: data.name || '',
email: data.email || '',
vendor_id: data.id,
booth_number: data.booth_number || '',
is_vendor: isVendor,
booth_mode: boothMode,
is_staff: isStaff,
permissions: permissions,
assistant_enabled: data.assistant_enabled !== false,
theme_preference: data.theme_preference || 'dark',
font_size_preference: data.font_size_preference || 'medium',
canAccessVendorBooth: canAccessVendorBooth,
canViewVendorDashboard: canAccessVendorBooth && permissions.role_view_dashboard,
canManageItems: isStaff || (canAccessVendorBooth && permissions.role_manage_items),
canViewSales: (isStaff && permissions.role_view_sales) || (canAccessVendorBooth && permissions.role_view_sales),
canAccessAdminDashboard: isStaff && permissions.role_view_dashboard,
canProcessSales: isStaff && permissions.role_process_sales,
canManageRent: isStaff && permissions.role_manage_rent,
canViewReports: isStaff && permissions.role_view_reports,
canManageVendors: isStaff && permissions.role_manage_vendors,
canManageStudio: isStaff && permissions.role_manage_studio,
canInventoryVerify: isStaff && permissions.role_inventory_verify,
canChangeSettings: role === 'admin',
canUseAiAssistant: permissions.role_view_ai_assistant && data.assistant_enabled !== false,
canViewPayouts: isStaff && (permissions.role_manage_rent || permissions.role_view_reports)
};
}
function _accessAllowed(session, access) {
if (typeof access === 'function') {
return access(session);
}
if (typeof access === 'string') {
return !!session[access];
}
if (Array.isArray(access)) {
return access.every(function (key) { return !!session[key]; });
}
return !!access;
}
function _homeHref(session) {
if (session.role === 'admin') {
return '/admin/index.html';
}
if (session.canAccessVendorBooth && session.booth_mode) {
return '/vendor/dashboard.html';
}
if (session.canManageVendors || session.canManageRent || session.canViewReports || session.canManageStudio || session.canInventoryVerify) {
return '/admin/index.html';
}
if (session.role === 'admin' && session.canAccessAdminDashboard) {
return '/admin/index.html';
}
if (session.role === 'cashier' && session.canProcessSales) {
return '/pos/index.html';
}
if (session.canAccessVendorBooth) {
return '/vendor/dashboard.html';
}
if (session.canAccessAdminDashboard) {
return session.role === 'admin' ? '/admin/index.html' : '/pos/index.html';
}
return '/vendor/login.html';
}
function _requiredForHref(href) {
if (!href) return null;
if (href.indexOf('/admin/settings.html') === 0) return 'canChangeSettings';
if (href.indexOf('/admin/vendors.html') === 0) return 'canManageVendors';
if (href.indexOf('/admin/reports.html') === 0) return 'canViewReports';
if (href.indexOf('/admin/eod-reports.html') === 0) return 'canViewReports';
if (href.indexOf('/admin/payouts.html') === 0) return 'canViewPayouts';
if (href.indexOf('/admin/rent.html') === 0) return 'canManageRent';
if (href.indexOf('/admin/studio.html') === 0) return 'canManageStudio';
if (href.indexOf('/admin/inventory-verify.html') === 0) return 'canInventoryVerify';
if (href.indexOf('/admin/index.html') === 0) return 'canAccessAdminDashboard';
if (href.indexOf('/pos/index.html') === 0 || href.indexOf('/pos/register.html') === 0) return 'canProcessSales';
if (href.indexOf('/vendor/items.html') === 0) return 'canManageItems';
if (href.indexOf('/vendor/dashboard.html') === 0) return 'canViewVendorDashboard';
if (href.indexOf('/vendor/booth-showcase.html') === 0) return 'canAccessVendorBooth';
return null;
}
function _markUnavailable(el) {
el.style.display = 'none';
el.setAttribute('aria-hidden', 'true');
el.setAttribute('tabindex', '-1');
}
function _showBlockedState(session, title, message) {
var existing = document.getElementById('bmm-access-blocked');
if (existing) existing.remove();
var overlay = document.createElement('div');
overlay.id = 'bmm-access-blocked';
overlay.className = 'bmm-blocked-overlay';
overlay.innerHTML =
'<div class="bmm-blocked-card" role="alertdialog" aria-modal="true" aria-labelledby="bmm-blocked-title">' +
'<h1 id="bmm-blocked-title" class="bmm-blocked-title">' + title + '</h1>' +
'<p class="bmm-blocked-message">' + message + '</p>' +
'<div class="bmm-blocked-actions">' +
'<a class="btn btn-primary" href="' + _homeHref(session) + '">Go To My Home</a>' +
'<a class="btn btn-secondary" href="/vendor/login.html">Back To Login</a>' +
'</div>' +
'</div>';
document.body.appendChild(overlay);
document.body.classList.add('bmm-blocked');
}
async function loadSession(force) {
if (!force && _sessionCache) return _sessionCache;
var token = null;
try {
token = sessionStorage.getItem('bmm_token');
} catch (e) {}
if (!token) return null;
var res;
try {
res = await fetch('/api/v1/auth/me', {
headers: { 'Authorization': 'Bearer ' + token }
});
} catch (err) {
throw new Error('Unable to verify your session right now.');
}
if (res.status === 401) {
if (typeof clearToken === 'function') clearToken();
window.location.href = '/vendor/login.html';
return null;
}
if (!res.ok) {
throw new Error('Unable to load your permissions right now.');
}
var data = await res.json();
try {
sessionStorage.setItem('bmm_user', JSON.stringify({
role: data.role,
name: data.name,
id: data.id
}));
} catch (e) {}
_sessionCache = _deriveSession(data);
document.documentElement.setAttribute('data-user-role', _sessionCache.role || '');
document.documentElement.setAttribute('data-booth-mode', _sessionCache.booth_mode ? '1' : '0');
applyNavigationAccess(_sessionCache);
return _sessionCache;
}
async function requirePageAccess(options) {
options = options || {};
var session = await loadSession(options.force);
if (!session) {
window.location.href = '/vendor/login.html';
return null;
}
if (options.userNameId) {
var nameEl = document.getElementById(options.userNameId);
if (nameEl) nameEl.textContent = session.name || 'User';
}
if (options.access && !_accessAllowed(session, options.access)) {
_showBlockedState(
session,
options.title || 'Access Restricted',
options.message || 'This page is not enabled for your role.'
);
return null;
}
return session;
}
function applyNavigationAccess(session, root) {
root = root || document;
root.querySelectorAll('a[href]').forEach(function (link) {
var required = _requiredForHref(link.getAttribute('href'));
if (!required) return;
if (!session[required]) _markUnavailable(link);
});
if (session.role !== 'admin') {
root.querySelectorAll('.admin-only-nav, .admin-only-dash, .admin-only').forEach(_markUnavailable);
}
}
function logout() {
if (typeof clearToken === 'function') clearToken();
window.location.href = '/vendor/login.html';
}
window.bmmAuth = {
loadSession: loadSession,
requirePageAccess: requirePageAccess,
applyNavigationAccess: applyNavigationAccess,
logout: logout,
homeHref: _homeHref,
resetCache: function () { _sessionCache = null; }
};
})();